mapper.insert:
INSERT INTO refresh_tokens (
    member_id, device_id, token_hash, status, expires_at
) VALUES (
    #{memberId}, #{deviceId}, #{tokenHash}, #{status}, #{expiresAt}
)

mapper.select:
SELECT id, member_id, device_id, token_hash, status, expires_at, created_at, revoked_at
FROM refresh_tokens
WHERE token_hash = #{tokenHash}

mapper.update:
UPDATE refresh_tokens
SET status = 'REVOKED',
    revoked_at = #{revokedAt}
WHERE token_hash = #{tokenHash}
  AND status = 'ACTIVE'

UPDATE refresh_tokens
SET status = 'REVOKED',
    revoked_at = #{revokedAt}
WHERE member_id = #{memberId}
  AND device_id = #{deviceId}
  AND status = 'ACTIVE'
